#!/usr/bin/env python3
"""run.py (self-contained) — unpacks the embedded model package, then runs.

Flat single-file layout so it uploads to GitHub with no folders to mangle.
The entire mlb_betting_model package is embedded as base64 below and written
to disk at startup, then imported normally.
"""
import base64 as _b64, io as _io, zipfile as _zip, os as _os, sys as _sys

_PKG_B64 = ""

def _unpack_package():
    if _os.path.isdir("mlb_betting_model"):
        return
    with _zip.ZipFile(_io.BytesIO(_b64.b64decode(_PKG_B64))) as zf:
        zf.extractall(".")

_unpack_package()
if "." not in _sys.path:
    _sys.path.insert(0, ".")

from __future__ import annotations

import html
import sys
from datetime import datetime, timezone, timedelta

from mlb_betting_model.worker_client import WorkerClient
from mlb_betting_model.parsers import parse_schedule, parse_odds, enrich_pitchers_from_boxscore
from mlb_betting_model.config import DEFAULT_BOOKMAKERS
from mlb_betting_model.v14.environment import run_environment
from mlb_betting_model.v14.requirements import run_self_check
from mlb_betting_model.v14 import (
    V14League, detect_advantages, handedness_offense_rank,
    starter_adjustment, bullpen_adjustment,
    score_moneyline, score_run_line, score_total_v14,
)

ET = timezone(timedelta(hours=-4))


def american_to_prob(px: float) -> float:
    return (-px / (-px + 100.0)) if px < 0 else (100.0 / (px + 100.0))


def build_games(run_date: str):
    client = WorkerClient()
    year = int(run_date[:4])
    payloads = client.daily_payloads(
        date=run_date, year=year,
        markets="h2h,spreads,totals", bookmakers=DEFAULT_BOOKMAKERS,
        include_advanced_stats=False, include_transactions=False,
    )
    games = parse_schedule(payloads.schedule)
    try:
        games, _ = enrich_pitchers_from_boxscore(games, client)
    except Exception as exc:
        print(f"[enrich] {exc}", file=sys.stderr)

    now = datetime.now(timezone.utc)
    pregame = []
    for g in games:
        try:
            ct = datetime.fromisoformat((g.start_time or "").replace("Z", "+00:00"))
            if ct > now:
                pregame.append(g)
        except Exception:
            pregame.append(g)
    games = pregame
    odds = parse_odds(payloads.odds)

    name_map = {}
    for g in games:
        name_map[g.away_team.id] = g.away_team.name
        name_map[g.home_team.id] = g.home_team.name

    try:
        weather_feed = client.weather_all()
    except Exception:
        weather_feed = None

    league = V14League(client, season=year)
    league.build(name_map=name_map)

    odds_idx = {}
    for o in odds:
        odds_idx.setdefault(f"{o.away_team} @ {o.home_team}", []).append(o)

    out = []
    for g in games:
        try:
            aid, hid = g.away_team.id, g.home_team.id
            an, hn = g.away_team.name, g.home_team.name
            ap, hp = league.profiles[aid], league.profiles[hid]
            ah = league.client.pitcher_hand(g.away_pitcher.id) if g.away_pitcher else None
            hh = league.client.pitcher_hand(g.home_pitcher.id) if g.home_pitcher else None
            a_start = league.client.pitcher_season(g.away_pitcher.id) if g.away_pitcher else None
            h_start = league.client.pitcher_season(g.home_pitcher.id) if g.home_pitcher else None

            a_off = handedness_offense_rank(league.off(aid), ap, hh)
            h_off = handedness_offense_rank(league.off(hid), hp, ah)
            distinct = league.windows_distinct(aid) and league.windows_distinct(hid)

            adv = []
            adv += detect_advantages(an, a_off, league.deff(hid), distinct)
            adv += detect_advantages(hn, h_off, league.deff(aid), distinct)

            h_suppress = 0.6 * starter_adjustment(h_start) + 0.25 * bullpen_adjustment(hp.bullpen_opp_rpg) + 0.15
            a_suppress = 0.6 * starter_adjustment(a_start) + 0.25 * bullpen_adjustment(ap.bullpen_opp_rpg) + 0.15
            a_rpg = ap.off_season.runs_per_game or 4.3
            h_rpg = hp.off_season.runs_per_game or 4.3
            away_runs = a_rpg * h_suppress
            home_runs = h_rpg * a_suppress * 1.03
            env = run_environment(g.venue_name, weather_feed)
            model_total_neutral = away_runs + home_runs
            model_total = model_total_neutral * env['combined']
            exp = 1.83
            hwp = home_runs ** exp / (home_runs ** exp + away_runs ** exp) if away_runs > 0 and home_runs > 0 else 0.5

            quotes = odds_idx.get(f"{an} @ {hn}", [])
            h2h = [q for q in quotes if q.market_key == "h2h"]
            totals = [q for q in quotes if q.market_key == "totals"]
            mkt_home_novig = None
            if len(h2h) >= 2:
                hq = next((q for q in h2h if q.outcome_name == hn), None)
                aq = next((q for q in h2h if q.outcome_name == an), None)
                if hq and aq and hq.price and aq.price:
                    ph, pa = american_to_prob(hq.price), american_to_prob(aq.price)
                    mkt_home_novig = ph / (ph + pa)
            mkt_total = None
            if totals:
                pts = [q.point for q in totals if q.point is not None]
                if pts:
                    mkt_total = sorted(pts)[len(pts) // 2]

            ml = score_moneyline(an, hn, adv, hwp, mkt_home_novig)
            tot = score_total_v14(model_total_neutral, mkt_total, env["combined"], over_supporting={"o": 0.5})
            rl = score_run_line(ml, hwp, hwp >= 0.5)

            out.append({
                "away": an, "home": hn,
                "start": g.start_time, "venue": g.venue_name,
                "mkt_total": mkt_total, "model_total": round(model_total, 1),
                "hwp": hwp, "adv": adv, "env_note": env["note"],
                "verdicts": {"Moneyline": ml, "Run Line": rl, "Total": tot},
                "windows_ok": distinct,
            })
        except Exception as exc:
            print(f"[game] {getattr(g, 'matchup', '?')}: {exc}", file=sys.stderr)
    return out


# ---------- HTML rendering ----------
VERDICT_CLASS = {"PLAY": "play", "LEAN": "lean", "PASS": "pass"}


def render_game_card(gm: dict) -> str:
    adv_html = ""
    away_adv = [a for a in gm["adv"] if a.side == gm["away"]]
    home_adv = [a for a in gm["adv"] if a.side == gm["home"]]
    for team, adv in ((gm["away"], away_adv), (gm["home"], home_adv)):
        if not adv:
            continue
        rows = "".join(
            f'<li><span class="stars">{"★" * a.stars}{"☆" * (5 - a.stars)}</span> '
            f'<b>{html.escape(a.stat)}</b> <span class="detail">{html.escape(a.detail)}</span></li>'
            for a in sorted(adv, key=lambda x: -x.stars)
        )
        adv_html += f'<div class="adv-block"><div class="adv-team">{html.escape(team)} advantages</div><ul>{rows}</ul></div>'
    if not gm["adv"]:
        adv_html = '<div class="adv-block muted">No stacked advantages — leaning PASS</div>'

    dials = ""
    for mkt in ("Moneyline", "Run Line", "Total"):
        v = gm["verdicts"][mkt]
        cls = VERDICT_CLASS[v.verdict]
        dials += (
            f'<div class="dial {cls}">'
            f'<div class="dial-mkt">{mkt}</div>'
            f'<div class="dial-score">{v.score}</div>'
            f'<div class="dial-verdict">{v.verdict}</div>'
            f'<div class="dial-pick">{html.escape(v.pick)}</div>'
            f'</div>'
        )

    flag = "" if gm["windows_ok"] else '<span class="warn">recent-form windows unavailable</span>'
    start = (gm["start"] or "").replace("T", " ").replace("Z", " UTC")
    return f"""
    <div class="card">
      <div class="card-head">
        <div class="matchup">{html.escape(gm['away'])} <span class="at">@</span> {html.escape(gm['home'])}</div>
        <div class="meta">{html.escape(start)} · {html.escape(gm['venue'] or '')} · line {gm['mkt_total']} · model {gm['model_total']} · home win {gm['hwp']:.0%} {flag}</div>
        <div class="meta">{html.escape(gm.get('env_note',''))}</div>
      </div>
      <div class="dials">{dials}</div>
      <div class="advs">{adv_html}</div>
    </div>
    """


def render_page(games: list[dict], run_date: str) -> str:
    plays = []
    for gm in games:
        for mkt, v in gm["verdicts"].items():
            if v.verdict in ("PLAY", "LEAN"):
                plays.append((gm, mkt, v))
    order = {"PLAY": 0, "LEAN": 1}
    plays.sort(key=lambda x: (order[x[2].verdict], -x[2].score))
    n_play = sum(1 for _, _, v in plays if v.verdict == "PLAY")
    n_lean = sum(1 for _, _, v in plays if v.verdict == "LEAN")

    play_rows = ""
    for gm, mkt, v in plays:
        cls = VERDICT_CLASS[v.verdict]
        play_rows += (
            f'<tr class="{cls}"><td>{v.verdict}</td><td>{v.score}</td>'
            f'<td>{html.escape(gm["away"])} @ {html.escape(gm["home"])}</td>'
            f'<td>{mkt}</td><td>{html.escape(v.pick)}</td></tr>'
        )
    if not plays:
        play_rows = '<tr><td colspan="5" class="muted">No PLAYs or LEANs — model passes the whole slate</td></tr>'

    cards = "".join(render_game_card(g) for g in games)
    updated = datetime.now(ET).strftime("%Y-%m-%d %I:%M %p ET")

    return f"""<!doctype html>
<html lang="en"><head>
<meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1">
<title>MLB Model — {run_date}</title>
<style>
:root {{ --bg:#0f1115; --card:#1a1d24; --line:#2a2f3a; --txt:#e6e8ec; --muted:#8a909c;
        --play:#22c55e; --lean:#eab308; --pass:#6b7280; --accent:#3b82f6; }}
* {{ box-sizing:border-box; }}
body {{ margin:0; background:var(--bg); color:var(--txt); font:15px/1.5 -apple-system,Segoe UI,Roboto,sans-serif; }}
header {{ padding:20px; border-bottom:1px solid var(--line); position:sticky; top:0; background:var(--bg); z-index:2; }}
h1 {{ margin:0; font-size:20px; }}
.sub {{ color:var(--muted); font-size:13px; margin-top:4px; }}
.wrap {{ max-width:980px; margin:0 auto; padding:16px; }}
.summary {{ background:var(--card); border:1px solid var(--line); border-radius:12px; padding:16px; margin-bottom:20px; }}
.summary h2 {{ margin:0 0 10px; font-size:16px; }}
table {{ width:100%; border-collapse:collapse; }}
td,th {{ text-align:left; padding:8px 10px; border-bottom:1px solid var(--line); font-size:14px; }}
tr.play td:first-child {{ color:var(--play); font-weight:700; }}
tr.lean td:first-child {{ color:var(--lean); font-weight:700; }}
.card {{ background:var(--card); border:1px solid var(--line); border-radius:12px; padding:16px; margin-bottom:16px; }}
.card-head .matchup {{ font-size:17px; font-weight:700; }}
.at {{ color:var(--muted); font-weight:400; }}
.meta {{ color:var(--muted); font-size:12px; margin-top:3px; }}
.warn {{ color:var(--lean); }}
.dials {{ display:flex; gap:10px; margin:14px 0; flex-wrap:wrap; }}
.dial {{ flex:1; min-width:140px; border:1px solid var(--line); border-radius:10px; padding:10px; text-align:center; }}
.dial-mkt {{ font-size:12px; color:var(--muted); text-transform:uppercase; letter-spacing:.04em; }}
.dial-score {{ font-size:26px; font-weight:800; margin:2px 0; }}
.dial-verdict {{ font-size:13px; font-weight:700; }}
.dial-pick {{ font-size:12px; color:var(--muted); margin-top:2px; min-height:1em; }}
.dial.play {{ border-color:var(--play); }} .dial.play .dial-verdict {{ color:var(--play); }}
.dial.lean {{ border-color:var(--lean); }} .dial.lean .dial-verdict {{ color:var(--lean); }}
.dial.pass .dial-verdict {{ color:var(--pass); }}
.advs {{ display:flex; gap:16px; flex-wrap:wrap; }}
.adv-block {{ flex:1; min-width:220px; }}
.adv-team {{ font-size:12px; text-transform:uppercase; color:var(--accent); letter-spacing:.04em; margin-bottom:4px; }}
.adv-block ul {{ margin:0; padding-left:0; list-style:none; }}
.adv-block li {{ font-size:13px; padding:2px 0; }}
.stars {{ color:var(--lean); letter-spacing:-1px; }}
.detail {{ color:var(--muted); font-size:12px; }}
.muted {{ color:var(--muted); }}
.disclaimer {{ color:var(--muted); font-size:12px; margin-top:24px; padding:14px; border:1px dashed var(--line); border-radius:10px; }}
</style></head>
<body>
<header><div class="wrap" style="padding:0">
  <h1>MLB Rank-and-Advantage Model</h1>
  <div class="sub">Slate {run_date} · updated {updated} · ML / Run Line / Total (real DK & FD lines) · paper only</div>
</div></header>
<div class="wrap">
  <div class="summary">
    <h2>Play sheet — {n_play} PLAY · {n_lean} LEAN</h2>
    <table>
      <tr><th>Verdict</th><th>Score</th><th>Game</th><th>Market</th><th>Pick</th></tr>
      {play_rows}
    </table>
  </div>
  {cards}
  <div class="disclaimer">
    Decision support only — NOT proven +EV. This model has not been validated to beat the market;
    track results and bet nothing real until a clean sample shows the plays win. F5 and NRFI are
    omitted because real market lines for them are not available through the free data source.
  </div>
</div>
</body></html>"""


def requirements_report() -> tuple[bool, str]:
    ctx = {
        "park_active": True, "weather_active": True, "env_divergence_active": True,
        "real_form_active": True, "handedness_active": True, "starter_active": True,
        "bullpen_active": True, "sos_regression_active": True, "real_lines_only": True,
        "juice_cap_active": True, "window_integrity_active": True, "no_real_money": True,
    }
    return run_self_check(ctx)


def lock_picks(games: list[dict], run_date: str) -> int:
    """Freeze every PLAY/LEAN with the LINE IT WAS TAKEN AT and a pull timestamp.

    This is what makes the midnight-line theory testable: picks and their lines
    are locked at pull time and appended to docs/locked_picks.jsonl, which is
    committed to the repo. They cannot be revised after results come in, so
    grading is honest. Each row also records the model total and home win prob
    so we can later compare the locked (midnight) line to the closing line.
    """
    import json as _json
    pulled_at = datetime.now(ET).isoformat()
    rows = []
    for gm in games:
        for mkt, v in gm["verdicts"].items():
            if v.verdict in ("PLAY", "LEAN"):
                rows.append({
                    "pulled_at": pulled_at,
                    "slate_date": run_date,
                    "game": f"{gm['away']} @ {gm['home']}",
                    "market": mkt,
                    "pick": v.pick,
                    "verdict": v.verdict,
                    "score": v.score,
                    "line_at_pull": gm.get("mkt_total") if mkt == "Total" else None,
                    "model_total": gm.get("model_total"),
                    "home_win_prob": round(gm.get("hwp", 0.0), 4),
                    "env_note": gm.get("env_note", ""),
                    "graded": False,   # filled in later when results are checked
                    "result": None,
                })
    import os
    os.makedirs("docs", exist_ok=True)
    path = "docs/locked_picks.jsonl"
    with open(path, "a") as f:
        for r in rows:
            f.write(_json.dumps(r) + "\n")
    return len(rows)


def main():
    run_date = datetime.now(ET).strftime("%Y-%m-%d")
    ok, report = requirements_report()
    print(report)
    try:
        games = build_games(run_date)
    except Exception as exc:
        games = []
        print(f"[fatal] {exc}", file=sys.stderr)
    import os
    os.makedirs("docs", exist_ok=True)
    with open("docs/index.html", "w") as f:
        f.write(render_page(games, run_date))
    n_locked = lock_picks(games, run_date)
    print(f"Wrote docs/index.html for {run_date} ({len(games)} games)")
    print(f"Locked {n_locked} picks at the midnight line -> docs/locked_picks.jsonl")


if __name__ == "__main__":
    main()
